#!/usr/bin/env python3\n"""\nBMC-12e Edge-Count Neighborhood Sweep Runner.\n\nPurpose\n-------\nTest whether the BMC-12c feature-retention pattern at N=81 persists around\nneighboring matched edge counts.\n\nFor each edge count N:\n  - build top-N graphs for all-feature baseline and feature leave-one-out cases\n  - write old-style runner inputs/configs\n  - call scripts/bmc07_backbone_variation_runner.py\n  - collect backbone_variant_summary.csv\n  - write decision and variant summaries across all N\n\nThis runner uses the reconciled BMC08c-derived feature table.\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport csv\nimport json\nimport math\nimport shutil\nimport subprocess\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional, Sequence, Tuple\n\ntry:\n    import yaml\nexcept ImportError as exc:\n    raise SystemExit("Missing dependency: PyYAML. Install with: python3 -m pip install pyyaml") from exc\n\n\nRow = Dict[str, Any]\n\n\ndef load_yaml(path: Path) -> Dict[str, Any]:\n    with path.open("r", encoding="utf-8") as f:\n        data = yaml.safe_load(f)\n    if not isinstance(data, dict):\n        raise ValueError(f"Config is not a mapping: {path}")\n    return data\n\n\ndef write_yaml(path: Path, data: Dict[str, Any]) -> None:\n    with path.open("w", encoding="utf-8") as f:\n        yaml.safe_dump(data, f, sort_keys=False, allow_unicode=True)\n\n\ndef read_csv(path: Path) -> List[Dict[str, str]]:\n    with path.open("r", encoding="utf-8", newline="") as f:\n        rows = list(csv.DictReader(f))\n    if not rows:\n        raise ValueError(f"CSV has no rows: {path}")\n    return [dict(r) for r in rows]\n\n\ndef write_csv(path: Path, rows: Sequence[Dict[str, Any]], fieldnames: Sequence[str]) -> None:\n    path.parent.mkdir(parents=True, exist_ok=True)\n    with path.open("w", encoding="utf-8", newline="") as f:\n        writer = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")\n        writer.writeheader()\n        for row in rows:\n            writer.writerow(row)\n\n\ndef project_path(root: Path, value: str) -> Path:\n    p = Path(value)\n    return p if p.is_absolute() else root / p\n\n\ndef data_relative_path(root: Path, path: Path) -> str:\n    rel = path.relative_to(root / "data")\n    parts = rel.parts\n    if len(parts) >= 1 and parts[0] == "bmc12e_edgecount_sweep_inputs":\n        return "../" + str(rel)\n    return str(rel)\n\n\ndef safe_id(value: str) -> str:\n    return "".join(ch if (ch.isalnum() or ch in "_-.") else "_" for ch in value)\n\n\ndef as_float(value: Any, column: str, row_index: int) -> float:\n    if value is None or value == "":\n        raise ValueError(f"Missing numeric value in column {column!r}, row {row_index}")\n    x = float(value)\n    if not math.isfinite(x):\n        raise ValueError(f"Non-finite numeric value in column {column!r}, row {row_index}: {value!r}")\n    return x\n\n\ndef derive_missing_features(rows: List[Dict[str, Any]]) -> List[str]:\n    if not rows:\n        return []\n    columns = set(rows[0].keys())\n    notes: List[str] = []\n\n    if "feature_shape_factor" not in columns:\n        needed = {"L_major_raw", "L_minor_raw"}\n        missing = needed - columns\n        if missing:\n            raise ValueError(f"Cannot derive feature_shape_factor; missing columns: {sorted(missing)}")\n        for idx, row in enumerate(rows, start=1):\n            a = as_float(row["L_major_raw"], "L_major_raw", idx)\n            b = as_float(row["L_minor_raw"], "L_minor_raw", idx)\n            denom = min(a, b)\n            if denom == 0.0:\n                raise ValueError(f"Cannot derive feature_shape_factor in row {idx}: denominator zero")\n            row["feature_shape_factor"] = max(a, b) / denom\n        notes.append("feature_shape_factor derived in memory")\n\n    columns = set(rows[0].keys())\n\n    if "feature_spectral_index" not in columns:\n        if "m_ref_raw" not in columns:\n            raise ValueError("Cannot derive feature_spectral_index; missing m_ref_raw")\n        for idx, row in enumerate(rows, start=1):\n            row["feature_spectral_index"] = as_float(row["m_ref_raw"], "m_ref_raw", idx)\n        notes.append("feature_spectral_index derived in memory")\n\n    return notes\n\n\ndef validate_rows(rows: List[Dict[str, Any]], node_id_column: str, features: Sequence[str]) -> None:\n    columns = set(rows[0].keys())\n    missing = [c for c in [node_id_column, *features] if c not in columns]\n    if missing:\n        raise ValueError(f"Feature table missing columns: {missing}. Available: {sorted(columns)}")\n\n    node_ids = [str(r[node_id_column]) for r in rows]\n    if len(node_ids) != len(set(node_ids)):\n        raise ValueError(f"Duplicate node IDs in column {node_id_column!r}")\n\n\ndef mean(values: Sequence[float]) -> float:\n    return sum(values) / len(values) if values else float("nan")\n\n\ndef z_standardize(\n    rows: List[Dict[str, Any]],\n    features: Sequence[str],\n    *,\n    ddof: int,\n    zero_std_policy: str,\n) -> List[List[float]]:\n    matrix: List[List[float]] = []\n    for r_idx, row in enumerate(rows, start=1):\n        matrix.append([as_float(row[f], f, r_idx) for f in features])\n\n    n = len(matrix)\n    if n <= ddof:\n        raise ValueError(f"Cannot standardize with n={n}, ddof={ddof}")\n\n    cols = list(zip(*matrix))\n    means = [mean([float(x) for x in col]) for col in cols]\n    stds: List[float] = []\n\n    for feature, col, mu in zip(features, cols, means):\n        var = sum((float(x) - mu) ** 2 for x in col) / (n - ddof)\n        std = math.sqrt(var)\n        if std == 0.0:\n            if zero_std_policy == "error":\n                raise ValueError(f"Feature has zero standard deviation: {feature}")\n            if zero_std_policy == "drop_to_zero":\n                std = 1.0\n            else:\n                raise ValueError(f"Unknown zero_std_policy: {zero_std_policy}")\n        stds.append(std)\n\n    return [[(x - mu) / sd for x, mu, sd in zip(row, means, stds)] for row in matrix]\n\n\ndef all_pair_weights(node_ids: Sequence[str], z: Sequence[Sequence[float]]) -> List[Dict[str, Any]]:\n    pairs: List[Dict[str, Any]] = []\n    for i in range(len(node_ids)):\n        for j in range(i + 1, len(node_ids)):\n            dist = math.sqrt(sum((a - b) ** 2 for a, b in zip(z[i], z[j])))\n            weight = 1.0 / (1.0 + dist)\n            source, target = sorted((str(node_ids[i]), str(node_ids[j])))\n            pairs.append({\n                "source": source,\n                "target": target,\n                "distance": dist,\n                "weight": weight,\n            })\n    return pairs\n\n\ndef select_top_n(pair_rows: Sequence[Dict[str, Any]], n: int) -> List[Dict[str, Any]]:\n    if n <= 0:\n        raise ValueError(f"edge count N must be positive, got {n}")\n    if n > len(pair_rows):\n        raise ValueError(f"edge count N={n} exceeds possible pairs={len(pair_rows)}")\n    ordered = sorted(\n        (dict(r) for r in pair_rows),\n        key=lambda r: (-float(r["weight"]), str(r["source"]), str(r["target"])),\n    )\n    return ordered[:n]\n\n\ndef case_definitions(features: Sequence[str]) -> List[Tuple[str, str, List[str]]]:\n    cases: List[Tuple[str, str, List[str]]] = [("baseline_all_features", "", list(features))]\n    for f in features:\n        active = [x for x in features if x != f]\n        cases.append((f"drop_{f}", f, active))\n    return cases\n\n\ndef build_case_files_and_config(\n    *,\n    root: Path,\n    cfg: Dict[str, Any],\n    edge_count: int,\n    case_id: str,\n    dropped_feature: str,\n    edge_rows: Sequence[Dict[str, Any]],\n) -> Path:\n    input_root = project_path(root, cfg["generated"]["input_root"])\n    config_root = project_path(root, cfg["generated"]["config_root"])\n    legacy_output_root = project_path(root, cfg["generated"]["legacy_runner_output_root"])\n\n    n_id = f"N_{edge_count}"\n    case_safe = safe_id(case_id)\n\n    case_input_dir = input_root / n_id / case_safe\n    case_config_dir = config_root / n_id\n    case_output_dir = legacy_output_root / n_id / case_safe\n\n    case_input_dir.mkdir(parents=True, exist_ok=True)\n    case_config_dir.mkdir(parents=True, exist_ok=True)\n    case_output_dir.mkdir(parents=True, exist_ok=True)\n\n    rel_table = case_input_dir / "baseline_relational_table_real.csv"\n    rel_rows = [{"source": r["source"], "target": r["target"], "weight": r["weight"]} for r in edge_rows]\n    write_csv(rel_table, rel_rows, ["source", "target", "weight"])\n\n    node_src = project_path(root, cfg["inputs"]["reference_node_metadata"])\n    node_dst = case_input_dir / "node_metadata_real.csv"\n    shutil.copyfile(node_src, node_dst)\n\n    runner_config = {\n        "run": {\n            "run_id": f"BMC12e_N{edge_count}_{case_safe}",\n            "output_dir": str(case_output_dir.relative_to(root)),\n            "seed": 101,\n        },\n        "inputs": {\n            "baseline_relational_table": data_relative_path(root, rel_table),\n            "node_metadata": data_relative_path(root, node_dst),\n            "bmc04_reference_summary": None,\n            "pair_neighborhood_matrix": None,\n            "diffusion_distance_matrix": None,\n        },\n        "graph": dict(cfg["graph"]),\n        "perturbation": dict(cfg["perturbation"]),\n        "readouts": dict(cfg["readouts"]),\n        "decision": dict(cfg["decision"]),\n        "backbone_variants": dict(cfg["backbone_variants"]),\n    }\n\n    config_path = case_config_dir / f"{case_safe}.yaml"\n    write_yaml(config_path, runner_config)\n    return config_path\n\n\ndef compare_case(\n    *,\n    edge_count: int,\n    case_id: str,\n    dropped_feature: str,\n    rows: Sequence[Dict[str, str]],\n    reference_label: str,\n    reference_arm: str,\n) -> Dict[str, Any]:\n    retained = sum(\n        1\n        for r in rows\n        if r.get("decision_label") == reference_label and r.get("dominant_arm") == reference_arm\n    )\n    total = len(rows)\n    failed = total - retained\n    if total > 0 and retained == total:\n        status = "decision_retained"\n    elif retained > 0:\n        status = "decision_partially_retained"\n    else:\n        status = "decision_not_retained"\n\n    return {\n        "edge_count_target": edge_count,\n        "case_id": case_id,\n        "dropped_feature": dropped_feature,\n        "variant_count": total,\n        "retained_variant_count": retained,\n        "retained_fraction": retained / total if total else 0.0,\n        "failed_variant_count": failed,\n        "all_variants_retained": str(total > 0 and retained == total).lower(),\n        "any_failure": str(failed > 0).lower(),\n        "bmc12e_decision_status": status,\n    }\n\n\ndef find_runner_summary(root: Path, cfg: Dict[str, Any], edge_count: int, case_id: str) -> Path:\n    """\n    Locate backbone_variant_summary.csv from the legacy bmc07 runner.\n\n    The legacy runner may resolve output_dir relative to the project root,\n    data/, or the config directory. Check all known conventions.\n    """\n    legacy_output_root = project_path(root, cfg["generated"]["legacy_runner_output_root"])\n    case_safe = safe_id(case_id)\n    suffix = Path(f"N_{edge_count}") / case_safe / "backbone_variant_summary.csv"\n\n    candidates = [\n        root / "data" / legacy_output_root.relative_to(root) / suffix,\n        legacy_output_root / suffix,\n        root / "data" / "bmc12e_edgecount_sweep_configs" / legacy_output_root.relative_to(root) / suffix,\n    ]\n\n    for candidate in candidates:\n        if candidate.exists():\n            return candidate\n\n    checked = "\n".join(f"  {c}" for c in candidates)\n    raise FileNotFoundError(\n        f"Could not find backbone_variant_summary.csv for N={edge_count}, case={case_id}. Checked:\n{checked}"\n    )\n\ndef write_readout(path: Path, *, run_id: str, edge_counts: Sequence[int], decision_rows: Sequence[Dict[str, Any]]) -> None:\n    lines: List[str] = []\n    lines.append("# BMC-12e Edge-Count Neighborhood Sweep Readout")\n    lines.append("")\n    lines.append("## Run")\n    lines.append("")\n    lines.append(f"- run_id: `{run_id}`")\n    lines.append(f"- edge_counts: `{', '.join(str(x) for x in edge_counts)}`")\n    lines.append("")\n    lines.append("## Befund")\n    lines.append("")\n    lines.append("BMC-12e re-ran matched leave-one-out backbone decisions across neighboring edge counts.")\n    lines.append("")\n    lines.append("| N | case_id | dropped_feature | retained_variants | retained_fraction | status |")\n    lines.append("|---:|---|---:|---:|---:|---|")\n    for row in decision_rows:\n        lines.append(\n            "| {N} | {case} | {drop} | {retained}/{total} | {frac:.3f} | {status} |".format(\n                N=row["edge_count_target"],\n                case=row["case_id"],\n                drop=row["dropped_feature"] or "-",\n                retained=row["retained_variant_count"],\n                total=row["variant_count"],\n                frac=float(row["retained_fraction"]),\n                status=row["bmc12e_decision_status"],\n            )\n        )\n\n    lines.append("")\n    lines.append("## Interpretation")\n    lines.append("")\n    lines.append(\n        "If the N=81 pattern persists across neighboring N values, the BMC-12c result is less likely to be a single graph-size artifact. "\n        "If the pattern changes strongly, BMC-12c should be treated as a local decision-point result."\n    )\n    lines.append("")\n    lines.append("## Hypothesis")\n    lines.append("")\n    lines.append(\n        "A stable edge-count-neighborhood profile would support the hypothesis of structured joint-feature-basis sensitivity. "\n        "A fragmented profile would support the red-team concern that the BMC-12c result is graph-size sensitive."\n    )\n    lines.append("")\n    lines.append("## Open gap")\n    lines.append("")\n    lines.append(\n        "This sweep does not yet vary the decision thresholds. A separate BMC-12f decision-threshold / dominance-gap sweep remains necessary."\n    )\n    lines.append("")\n\n    path.write_text("\n".join(lines), encoding="utf-8")\n\n\ndef main() -> None:\n    ap = argparse.ArgumentParser(description="Run BMC-12e edge-count neighborhood sweep.")\n    ap.add_argument("--config", required=True)\n    ap.add_argument("--prepare-only", action="store_true")\n    args = ap.parse_args()\n\n    root = Path.cwd()\n    cfg = load_yaml(project_path(root, args.config))\n\n    run_id = str(cfg.get("run_id", "BMC12e_edgecount_neighborhood_sweep_open"))\n    python_bin = str(cfg.get("python_bin", "python3"))\n    variant_runner = project_path(root, cfg["variant_runner"])\n    final_output_root = project_path(root, cfg["generated"]["final_output_root"])\n    final_output_root.mkdir(parents=True, exist_ok=True)\n\n    feature_table = project_path(root, cfg["inputs"]["feature_table"])\n    rows: List[Dict[str, Any]] = [dict(r) for r in read_csv(feature_table)]\n    derive_notes = derive_missing_features(rows)\n\n    node_id_column = str(cfg.get("node_id_column", "node_id"))\n    features = [str(x) for x in cfg["features"]]\n    edge_counts = [int(x) for x in cfg["edge_counts"]]\n\n    validate_rows(rows, node_id_column, features)\n    node_ids = [str(r[node_id_column]) for r in rows]\n\n    standardization = cfg.get("standardization", {}) or {}\n    ddof = int(standardization.get("ddof", 0))\n    zero_std_policy = str(standardization.get("zero_std_policy", "error"))\n\n    configs_to_run: List[Tuple[int, str, str, Path]] = []\n    edge_inventory_rows: List[Dict[str, Any]] = []\n\n    for edge_count in edge_counts:\n        for case_id, dropped_feature, active_features in case_definitions(features):\n            z = z_standardize(rows, active_features, ddof=ddof, zero_std_policy=zero_std_policy)\n            pair_rows = all_pair_weights(node_ids, z)\n            selected = select_top_n(pair_rows, edge_count)\n\n            for er in selected:\n                out_row = dict(er)\n                out_row["edge_count_target"] = edge_count\n                out_row["case_id"] = case_id\n                out_row["dropped_feature"] = dropped_feature\n                edge_inventory_rows.append(out_row)\n\n            config_path = build_case_files_and_config(\n                root=root,\n                cfg=cfg,\n                edge_count=edge_count,\n                case_id=case_id,\n                dropped_feature=dropped_feature,\n                edge_rows=selected,\n            )\n            configs_to_run.append((edge_count, case_id, dropped_feature, config_path))\n\n    edge_inventory_path = final_output_root / "bmc12e_edgecount_sweep_edges_inventory.csv"\n    write_csv(\n        edge_inventory_path,\n        edge_inventory_rows,\n        ["edge_count_target", "case_id", "dropped_feature", "source", "target", "distance", "weight"],\n    )\n\n    if args.prepare_only:\n        print("BMC-12e prepare-only completed.")\n        print(f"Wrote edge inventory: {edge_inventory_path}")\n        for edge_count, case_id, _, config_path in configs_to_run:\n            print(f"N={edge_count} {case_id}: {config_path}")\n        return\n\n    for edge_count, case_id, _, config_path in configs_to_run:\n        cmd = [python_bin, str(variant_runner), "--config", str(config_path)]\n        print("Running:", " ".join(cmd))\n        result = subprocess.run(cmd, cwd=root)\n        if result.returncode != 0:\n            raise SystemExit(f"Variant runner failed for N={edge_count}, case={case_id} with exit code {result.returncode}")\n\n    reference_label = str(cfg["reference_decision"]["decision_label"])\n    reference_arm = str(cfg["reference_decision"]["dominant_arm"])\n\n    variant_rows_all: List[Dict[str, Any]] = []\n    decision_rows: List[Dict[str, Any]] = []\n\n    for edge_count, case_id, dropped_feature, _ in configs_to_run:\n        summary_path = find_runner_summary(root, cfg, edge_count, case_id)\n        variant_rows = read_csv(summary_path)\n\n        for row in variant_rows:\n            out_row = dict(row)\n            out_row["edge_count_target"] = edge_count\n            out_row["case_id"] = case_id\n            out_row["dropped_feature"] = dropped_feature\n            variant_rows_all.append(out_row)\n\n        decision_rows.append(\n            compare_case(\n                edge_count=edge_count,\n                case_id=case_id,\n                dropped_feature=dropped_feature,\n                rows=variant_rows,\n                reference_label=reference_label,\n                reference_arm=reference_arm,\n            )\n        )\n\n    decision_fields = [\n        "edge_count_target",\n        "case_id",\n        "dropped_feature",\n        "variant_count",\n        "retained_variant_count",\n        "retained_fraction",\n        "failed_variant_count",\n        "all_variants_retained",\n        "any_failure",\n        "bmc12e_decision_status",\n    ]\n\n    variant_fields = [\n        "edge_count_target",\n        "case_id",\n        "dropped_feature",\n        "variant_name",\n        "method",\n        "variant_parameters",\n        "backbone_node_count",\n        "off_backbone_node_count",\n        "coupling_edge_count",\n        "decision_label",\n        "dominant_arm",\n        "full_graph_arrangement_signal",\n        "backbone_only_arrangement_signal",\n        "off_backbone_only_arrangement_signal",\n        "coupling_only_arrangement_signal",\n    ]\n\n    decision_summary_path = final_output_root / "bmc12e_edgecount_sweep_decision_summary.csv"\n    variant_summary_path = final_output_root / "bmc12e_edgecount_sweep_variant_summary.csv"\n    metrics_path = final_output_root / "bmc12e_metrics.json"\n    readout_path = final_output_root / "bmc12e_edgecount_sweep_readout.md"\n\n    write_csv(decision_summary_path, decision_rows, decision_fields)\n    write_csv(variant_summary_path, variant_rows_all, variant_fields)\n\n    metrics = {\n        "run_id": run_id,\n        "edge_counts": edge_counts,\n        "feature_table": str(feature_table),\n        "features": features,\n        "derived_feature_notes": derive_notes,\n        "reference_decision": {"decision_label": reference_label, "dominant_arm": reference_arm},\n        "decision_summary": decision_rows,\n        "edge_inventory": str(edge_inventory_path),\n    }\n    metrics_path.write_text(json.dumps(metrics, indent=2, ensure_ascii=False), encoding="utf-8")\n\n    write_readout(readout_path, run_id=run_id, edge_counts=edge_counts, decision_rows=decision_rows)\n\n    print("BMC-12e edge-count neighborhood sweep completed.")\n    print(f"Wrote: {decision_summary_path}")\n    print(f"Wrote: {variant_summary_path}")\n    print(f"Wrote: {metrics_path}")\n    print(f"Wrote: {readout_path}")\n\n\nif __name__ == "__main__":\n    main()\n